import React, { useState, useEffect } from 'react';
import Sidebar from '../Layout/Sidebar';
import MessageList from './MessageList';
import InputArea from './InputArea';
import WelcomeScreen from './WelcomeScreen';
import useChat from '../../hooks/useChat';
import '../../styles/Chat.css';
import '../styles/chat-interface.css';

const ChatContainer = () => {
  const [sidebarCollapsed, setSidebarCollapsed] = useState(false);
  const [theme, setTheme] = useState('light');
  const [isMobile, setIsMobile] = useState(window.innerWidth <= 768);
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const [chatHistory, setChatHistory] = useState([]);
  const [currentChatId, setCurrentChatId] = useState(null);

  const {
    messages,
    inputMessage,
    setInputMessage,
    isLoading,
    isTyping,
    sendMessage,
    clearChat,
    sessionId
  } = useChat();

  useEffect(() => {
    const handleResize = () => {
      setIsMobile(window.innerWidth <= 768);
      if (window.innerWidth > 768) {
        setSidebarOpen(false);
      }
    };

    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  useEffect(() => {
    document.documentElement.setAttribute('data-theme', theme);
  }, [theme]);

  useEffect(() => {
    // Update chat history when messages change
    if (messages.length > 1 && sessionId) { // More than just welcome message
      setChatHistory(prev => {
        const existingChatIndex = prev.findIndex(chat => chat.id === sessionId);
        const chatData = {
          id: sessionId,
          messages: messages,
          timestamp: new Date(),
          title: messages.find(m => m.type === 'user')?.content || 'New Chat'
        };

        if (existingChatIndex >= 0) {
          const updated = [...prev];
          updated[existingChatIndex] = chatData;
          return updated;
        } else {
          return [chatData, ...prev];
        }
      });
      setCurrentChatId(sessionId);
    }
  }, [messages, sessionId]);

  const toggleSidebar = () => {
    if (isMobile) {
      setSidebarOpen(!sidebarOpen);
    } else {
      setSidebarCollapsed(!sidebarCollapsed);
    }
  };

  const toggleTheme = () => {
    setTheme(theme === 'light' ? 'dark' : 'light');
  };

  const handleNewChat = () => {
    clearChat();
    if (isMobile) {
      setSidebarOpen(false);
    }
  };

  const handleChatSelect = (chatId) => {
    // Load selected chat
    const selectedChat = chatHistory.find(chat => chat.id === chatId);
    if (selectedChat) {
      // You would implement chat loading logic here
      setCurrentChatId(chatId);
    }
    if (isMobile) {
      setSidebarOpen(false);
    }
  };

  const handleSuggestionClick = (suggestion) => {
    setInputMessage(suggestion);
  };

  return (
    <div className="study-buddy-container">
      <Sidebar
        isCollapsed={sidebarCollapsed}
        toggleSidebar={toggleSidebar}
        chatHistory={chatHistory}
        currentChatId={currentChatId}
        onChatSelect={handleChatSelect}
        onNewChat={handleNewChat}
        theme={theme}
        toggleTheme={toggleTheme}
        isMobile={isMobile}
        isOpen={sidebarOpen}
      />

      <div className="main-content">
        <div className="chat-header">
          <div className="chat-title">
            {isMobile && (
              <button className="mobile-menu-btn" onClick={toggleSidebar}>
                ☰
              </button>
            )}
            <span className="brand-icon">🤖</span>
            StudyBuddy AI
          </div>
          
          {!isMobile && (
            <button className="theme-toggle" onClick={toggleTheme}>
              {theme === 'dark' ? '☀️' : '🌙'}
            </button>
          )}
        </div>

        <div className="chat-container">
          <div className="messages-area">
            {messages.length <= 1 ? (
              <WelcomeScreen onSuggestionClick={handleSuggestionClick} />
            ) : (
              <MessageList messages={messages} isTyping={isTyping} />
            )}
          </div>
          
          <InputArea
            inputMessage={inputMessage}
            setInputMessage={setInputMessage}
            sendMessage={sendMessage}
            isLoading={isLoading}
          />
        </div>
      </div>
    </div>
  );
};

export default ChatContainer;
